import java.io.BufferedWriter;
import java.io.FileWriter;
import java.io.IOException;

import org.apache.commons.text.StringEscapeUtils;

public class XssSecureCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        try (BufferedWriter writer = new BufferedWriter(new FileWriter("index.html"))) {
            writer.write("<html>");
            writer.write("<body>");
            writer.write("<h1>User Input: " + StringEscapeUtils.escapeHtml4(userInput) + "</h1>");
            writer.write("</body>");
            writer.write("</html>");
        } catch (IOException e) {
            System.out.println("Error writing to file: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
